class Solution {
public:
    int findTheLongestBalancedSubstring(string s) {
        int n = s.length();
        for (int k = n/2; k >= 0; --k) {
            int len = 2 * k;
            for (int i = 0; i <= n - len; ++i) {
                bool valid = true;
                for (int j = 0; j < k; ++j) {
                    if (s[i + j] != '0') {
                        valid = false;
                        break;
                    }
                }
                if (!valid) continue;
                for (int j = 0; j < k; ++j) {
                    if (s[i + k + j] != '1') {
                        valid = false;
                        break;
                    }
                }
                if (valid) return len;
            }
        }
        return 0;
    }
};

